const body = ($input.first().json.body ?? $input.first().json) || {};

const clean = (v, max = 4000) =>
  (typeof v === 'string' ? v : '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, max);

const normalizeEmail = (v) => clean(v, 254).toLowerCase();
const normalizePhone = (v) => clean(v, 40).replace(/[^\d+]/g, '');

const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const phoneRe = /^[+\d][\d\s().-]{5,}$/;

const allowedInterests = new Set([
  'galatea',
  'cricchetto',
  'atlas',
  'igea',
  'hermes',
  'not_sure',
]);

const nome = clean(body.nome, 120);
const attivita = clean(body.attivita, 160);
const settore = clean(body.settore, 120);
const email = normalizeEmail(body.email);
const email_normalized = email;
const telefono = clean(body.telefono, 40);
const telefono_normalized = normalizePhone(body.telefono);
const citta = clean(body.citta, 120);
const prodotto_interesse = clean(body.prodotto_interesse, 40).toLowerCase();
const messaggio = clean(body.messaggio, 4000);

const consent =
  body.privacy_consent === 'Yes' ||
  body.privacy_consent === true ||
  body.privacy_consent === 'true';

const errors = [];

if (!nome) errors.push('nome');
if (!attivita) errors.push('attivita');
if (!settore) errors.push('settore');
if (!email || !emailRe.test(email)) errors.push('email');
if (!telefono || !phoneRe.test(telefono)) errors.push('telefono');
if (!messaggio) errors.push('messaggio');
if (!prodotto_interesse || !allowedInterests.has(prodotto_interesse)) {
  errors.push('prodotto_interesse');
}
if (!consent) errors.push('privacy_consent');

if (errors.length) {
  return [
    {
      json: {
        __ok: false,
        status: 400,
        error: 'Dati non validi',
        fields: errors,
      },
    },
  ];
}

const lead_id = `lead_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
const created_at = new Date().toISOString();

return [
  {
    json: {
      __ok: true,
      lead_id,
      created_at,
      nome,
      attivita,
      settore,
      email,
      email_normalized,
      telefono,
      telefono_normalized,
      citta,
      prodotto_interesse,
      messaggio,
      privacy_consent: 'Yes',
      source: 'website',
      status: 'new',
      owner_notified: false,
      customer_email_sent: false,
      customer_email_sent_at: '',
      note: '',
    },
  },
];

